window.__QUIZ_DATA__=[{"id":"objective>Physics>2013>1","subject":"Physics","year":"2013","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"The rising of a liquid in an open ended glass tube of narrow bore is","images":[],"options":{"A":"osmosis","B":"adhesion","C":"capillarity","D":"surface tension"},"answer":"C","explanation":"The rising of a liquid in an open-ended glass tube of narrow bore is due to capillarity. Capillarity is the ability of a liquid to flow in narrow spaces without the assistance of, or even in opposition to, external forces like gravity. It occurs because of intermolecular forces between the liquid and surrounding solid surfaces. Osmosis is the spontaneous net movement of solvent molecules through a semi-permeable membrane into a region of higher solute concentration, in the direction that tends to equalize the solute concentrations on the two sides. Adhesion is the tendency of dissimilar particles or surfaces to cling to one another, and surface tension is the elastic tendency of a fluid surface which makes it acquire the least surface area possible.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>2","subject":"Physics","year":"2013","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"Which of the following units is equivalent to the Watt?","images":[],"options":{"A":"kgm-2","B":"kgm2s-3","C":"Kgm2s-2","D":"kgm-2s-1"},"answer":"B","explanation":"Power=EnergyTime=Force x DistanceTime    =MLT-2xLT    = ML2T-3 = kgm2s-3.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>3","subject":"Physics","year":"2013","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"Which of the following statements about pressure in a liquid is correct?","images":[],"options":{"A":"The pressure in a liquid increases with depth","B":"The higher the density of a liquid, the lower the pressure it exerts","C":"Pressure in a liquid acts only in a direction perpendicular to the side of the containing vessel.","D":"Pressure is independent of the acceleration due to gravity"},"answer":"A","explanation":"Pressure in a liquid increases with depth. This is because pressure is defined as the force exerted per unit area. In a liquid, this force is due to the weight of the liquid above the point where the pressure is being measured. Therefore, the deeper you go into the liquid, the more liquid there is above you, and the greater the pressure. The other options are incorrect. The pressure in a liquid is not dependent on the density of the liquid, it does not act only in a direction perpendicular to the side of the containing vessel, and it is not independent of the acceleration due to gravity.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>4","subject":"Physics","year":"2013","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A block of wood of mass 5 kg is pulled on a platform by a force of 40N as illustrated in the diagram above. If the friction force, F experienced by the block is 12N, Calculate the magnitude of the acceleration of the block.","images":["data:image/png;base64,"],"options":{"A":"2.4 ms-2","B":"5.6 ms-2","C":"8.0 ms-2","D":"10.4 ms-2"},"answer":"B","explanation":"Netforce = mass x acceleration    (40 - 12) = 5a    28 = 5a    a = 5.6ms-2","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>5","subject":"Physics","year":"2013","type":"Objective","topic":"MOTION : SOLID FRICTION","question":"Solid friction, like viscosity, is","images":[],"options":{"A":"independent of the surface areas in contact","B":"independence of the relative motion between layers","C":"dependent on normal reaction","D":"in opposition to motion"},"answer":"D","explanation":"Viscosity is friction in fluid which acts in opposition to motion.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>6","subject":"Physics","year":"2013","type":"Objective","topic":"SPEED AND VELOCITY : CONCEPT OF SPEED","question":"The slope of linear distance-time graph represents","images":[],"options":{"A":"acceleration","B":"displacement","C":"speed","D":"velocity"},"answer":"C","explanation":"* The slope of any graph (m) = dy/dx or m = \u0394y/\u0394x    * The slope of distance - time graph: m = \u0394x / \u0394y = Speed.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2013>7","subject":"Physics","year":"2013","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A body of mass 2 kg is released from rest on a smooth plane inclined at an angle of 60o to the horizontal.   Calculate the acceleration of the body down the plane.  [g = 10 ms-2]","images":[],"options":{"A":"3.1ms-2","B":"5.2ms-2","C":"6.0 ms-2","D":"8.7 ms-2"},"answer":"D","explanation":"* a = gsin\u03b8 (if no friction)    * a = 10sin60o = 8.4ms-2.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>8","subject":"Physics","year":"2013","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"The total area under a force-velocity graph represents","images":[],"options":{"A":"energy","B":"momentum","C":"power","D":"pressure"},"answer":"C","explanation":"* The area of any graph is the product of the quantity on the y-axis  and that on the x-axis    * The area of force-velocity graph is the product of force and velocity which is equal to POWER.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>9","subject":"Physics","year":"2013","type":"Objective","topic":"MOTION : MOTION UNDER GRAVITY","question":"A body of mass 20 g projected vertically upwards in vacuum returns to the point of projection after 1.2s. [g = 10ms-2]     Calculate the speed of projection","images":[],"options":{"A":"0.6 ms-1","B":"1.2ms-1","C":"6.0 ms-1","D":"12.0 ms-1"},"answer":"C","explanation":"Mb(mass of the body) = 20g = 0.02kg    T (time of flight) = 1.2s    t (time taken to reach maximum height) = 0.6s; g = 10ms-2    * t = &radic;2H/g&nbsp;; gt2/2 = H    10x(0.6)2 / 2 = 1.80m    * There is an energy-conversion process: From K.E to P.E    K.E = P.E    1/2mv2 = mgh    v2 = 2gh    v2 = (20)(1.8)    v2 = 36    v = &radic;36&nbsp;    v = 6ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>10","subject":"Physics","year":"2013","type":"Objective","topic":"WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY","question":"A body of mass 20 g projected vertically upwards in vacuum returns to the point of projection after 1.2s. [g = 10ms-2]    Determine the potential energy of the body at the maximum height of its motion","images":[],"options":{"A":"0.36J","B":"0.72J","C":"360.00J","D":"720.00J"},"answer":"A","explanation":"m=20g=0.02kg,T=1.2s  T=2ug  1.2=2u10  2u=12  u=6ms-1  Atmaximumheight,v=0  t=T2=1.22=0.6s  v=u-gt  H=ut-12gt2  =6(0.6)-12\u00d710\u00d70.62  =3.6-1.8  =1.8m  PE=mgh=0.02\u00d710\u00d71.8  =0.36J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>11","subject":"Physics","year":"2013","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"Four co-planar forces of magnitudes 10N, 17N, 6N and 20N act at point O as shown in the diagram above.   Determine the magnitude of the resultant force.","images":["data:image/png;base64,"],"options":{"A":"53.0 N","B":"21.0 N","C":"7.0 N","D":"5.0 N"},"answer":"D","explanation":"Net horizontal force (\u2211fx) = 20 - 17    Net vertical force (\u2211fg) = 10 - 6    Resultant (R) = &radic;(\u2211fx)2 + (\u2211fy)2&nbsp;    R = &radic;32 + 42 &nbsp;    R = &radic;25&nbsp;    R = 5N.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>12","subject":"Physics","year":"2013","type":"Objective","topic":"SIMPLE HARMONIC MOTION : AMPLITUDE OF A BODY EXECUTING S.H.M","question":"The maximum displacement on either side of the equilibrium position of an object in simple harmonic motion represents","images":[],"options":{"A":"period","B":"amplitude","C":"wavelength","D":"frequency"},"answer":"B","explanation":"In simple harmonic motion, the maximum displacement from the equilibrium position is known as the amplitude. It is the greatest distance that the object moves from its equilibrium position. Therefore, the correct option is amplitude.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2013>13","subject":"Physics","year":"2013","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : FIRST LAW","question":"From Newton's first law of motion,","images":[],"options":{"A":"a body can only undergo transitional motion","B":"once a body remains at rest, no force acts on it","C":"the net force acting on a body in uniform linear motion is zero","D":"a body's inertia is its weight"},"answer":"C","explanation":"According to the Newtons First Law of Motion, 'a body at rest will continue to be at rest and a body moving with uniform motion will continue to be in this state of motion unless an external impressed force is applied'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>14","subject":"Physics","year":"2013","type":"Objective","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A body of mass 11kg is suspended from a ceiling by an aluminium wire of length 2m and diameter 2mm. Calculate the elastic energy stored in the wire.  [Young modulus of aluminium is 7.0 x 1010 Nm-2, g = 10ms-2, x = 3.14 ]","images":[],"options":{"A":"1.1 x 10-1 J","B":"5.5 x 10-2 J","C":"1.1 x 10-4 J","D":"5.5 x 10-5 J"},"answer":"B","explanation":"E = FL/Ae ; A = \u03c0r2    K.E = 1/2Fe   FlEA=e   e=110x227x1010x3.14x10-6    e = 10 x 10-1m    K.E=12x110x10-3   K.E = 5.5 x 10-2J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>15","subject":"Physics","year":"2013","type":"Objective","topic":"MACHINES :","question":"The velocity ratio of an incline plane","images":[],"options":{"A":"increase with increase in angle of inclination","B":"increase with decrease in the angle of inclination","C":"decrease with decrease in the angle of inclination","D":"is independent of the angle of inclination"},"answer":"B","explanation":"The velocity ratio of an inclined plane is the ratio of the effort applied to the load lifted. It is given by the formula 1/sin\u03b8, where \u03b8 is the angle of inclination. Therefore, as the angle of inclination increases, the velocity ratio decreases, and vice versa.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>16","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Which of the following types of thermometers is used for the calibration of other thermometers?","images":[],"options":{"A":"Liquid-in-glass thermometer","B":"Constant volume gas thermometer","C":"optical pyrometer","D":"Thermocouple"},"answer":"B","explanation":"The constant volume gas thermometer is used for the calibration of other thermometers because it is based on the absolute temperature scale, which is independent of the properties of any particular substance. This makes it the most accurate type of thermometer.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>17","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The magnitude of the expansion or contraction of a substance depends on the    I. temperature change    II. nature of the substance  III. size of the substance","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"I, II and III"},"answer":"D","explanation":"This can be deduced from    \u03b1=l2 - l1l1\u0394\u03b8   \u03b1 (linear expansivity) which varies from one material to the other.    Length(l) which also varies with temperature change (\u0394\u03b8)","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>18","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"High polished silvery surfaces are","images":[],"options":{"A":"poor absorbers and poor emitter of radiation","B":"good absorbers and good emitter of radiation","C":"good absorbers but poor emitters of radiation","D":"poor absorbers but good emitters of radiation"},"answer":"A","explanation":"High polished silvery surfaces are poor absorbers and poor emitters of radiation. This is because they reflect most of the radiation that falls on them, rather than absorbing it. Similarly, they are poor emitters because they do not have many free electrons to emit radiation.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2013>19","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"The volume of a given mass of gas at 270C and 800 mmHg is 76 cm3. Calculate its volume at s.t.p","images":[],"options":{"A":"10.0 cm3","B":"72.8 cm3","C":"60.0 cm3","D":"36.4 cm3"},"answer":"B","explanation":"From the general gas equation   P1V1T1=P2V2T2    P1 = 800mmHg, P2 = 760mmHg, V1 = 76cm3, V2 = ? T1 = 27 + 273 = 300k, T2 = 273k    800 x 76300=760 x V2273   8 x 763=760V2273    81=10V291   V2=72810=72.8cm3","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>20","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"The outlet of a bicycle pump is used to inflate a football. Why does the pressure of the air inside the pump increase as the pump handle is slowly pushed downward at constant temperature?","images":["data:image/png;base64,"],"options":{"A":"Momentum of the air molecules are increased","B":"volume occupied by the molecules are increased","C":"frequency of collision of the air molecules with the walls of the pump is increased","D":"molecules are colliding with one another in the system."},"answer":"C","explanation":"frequency of collision of the air molecules with the walls of the pump is increased","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>21","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : LATENT HEAT","question":"Ice of mass 10g at -5oC was completely converted to water at 0oC. Calculate the quantity of heat used.  [Specific heat capacity of ice = 2.1 Jg-1K-1; specific latent heat of fusion of ice = 336Jg-1]","images":[],"options":{"A":"105J","B":"3255J","C":"3465J","D":"16821J"},"answer":"C","explanation":"Total heat used = Specific heat capacity of ice + latent heat of fusion of ice    SHC of ice = mc\u0394\u03b8    = (10)(2.1)(5) = 105    LHF of ice = mlf    = (10)(336) = 3360    Total heat = 105 + 3360 = 3465J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>22","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"An electric heater has a resistance of 50\u03a9. When it is immersed in water and connected  to main source, it draws a current of 4A. Calculate the heat gained by the water if the heater is switched on for 2 minutes, assuming no heat losses to the surroundings","images":[],"options":{"A":"400 J","B":"1600 J","C":"24000 J","D":"96000 J"},"answer":"D","explanation":"Heat gained by the water = I2Rt    I = 4.0A, t = 2 minutes = 120seconds, R = 50\u2126    H = I2RT = 42 x 50 x 120 = 96000J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>23","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"When salt is dissolved in water, the freezing point of the water","images":[],"options":{"A":"increases","B":"decreases","C":"remains the same","D":"increase and later decreases"},"answer":"B","explanation":"When salt is dissolved in water, it disrupts the structure of the water molecules and makes it harder for them to form the ordered structure necessary for freezing. This means that the freezing point of the water decreases.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2013>24","subject":"Physics","year":"2013","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM","question":"The diagram above illustrates a waveform. Which of the points on the waveform are in phase?","images":["data:image/png;base64,"],"options":{"A":"P and R","B":"R and T","C":"P and T","D":"Q and S"},"answer":"C","explanation":"P and T are in phase as the angular displacement from P to T is 2 \u03c0","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>25","subject":"Physics","year":"2013","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The equation of a certain progressive transverse wave is y = 2 sin 2\u03c0 (1/0.01 - x/30). Where x and y are in cm, and t in seconds, calculate the period of the wave.","images":[],"options":{"A":"0.001s","B":"0.010s","C":"10.000s","D":"100.000s"},"answer":"B","explanation":"Given,    y=2sin2\u03c0(t0.01-x30)    Fromy=Asin2\u03c0(tF-x\u03bb)    tT=t0.01    T = 0.01secs.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>26","subject":"Physics","year":"2013","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"At which equation position should an object be placed in front of a concave mirror in order to obtain an image which is of the same size as the object?","images":[],"options":{"A":"At the centre of curvature","B":"At the principal focus","C":"Between the pole and the principal focus","D":"Between the centre of curvature and the principal focus"},"answer":"A","explanation":"An object placed on the centre of curvature of a concave mirror will produce an image of unit magnification; i.e the image size is the same as the object size.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>27","subject":"Physics","year":"2013","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"Images formed by a convex mirror are always","images":[],"options":{"A":"magnified","B":"behind the mirror","C":"real","D":"inverted"},"answer":"B","explanation":"A convex mirror, also known as a diverging mirror, always forms images that are virtual, upright, and reduced in size. This is because the light rays never actually meet, but rather they diverge upon reflection. Therefore, the image appears to be located behind the mirror.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2013>28","subject":"Physics","year":"2013","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The refractive index of a material is 1.5. Calculate the critical angle at the glass-air interface.","images":[],"options":{"A":"190","B":"210","C":"390","D":"420"},"answer":"D","explanation":"n=sinCsin90o   1.5=11.5=sinC1     c = sin-1(0.667)    c = 42o.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>29","subject":"Physics","year":"2013","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES","question":"A diverging lens of focal length 30cm produces an image 20cm from the lens. Determine the object distance","images":[],"options":{"A":"10cm","B":"12cm","C":"50cm","D":"60cm"},"answer":"B","explanation":"Since it's a diverging lens (concave) the image will be virtual. Hence the mirror equation becomes    1f=1u-1v      f = 30cm, v = 20cm    130=1u-120   130=20 - u20u   20u = 600 - 30 u    50U = 600    U = 12cm.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>30","subject":"Physics","year":"2013","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"Which of the following statements about the Galilean telescope is not correct?","images":[],"options":{"A":"The final image is inverted","B":"It is shorter than terrestrial telescope","C":"The final image is erect","D":"It has a small field of view"},"answer":"A","explanation":"The Galilean telescope, which uses a convex objective lens and a concave eyepiece, produces an erect (upright) image, not an inverted one. Therefore, the statement 'The final image is inverted' (option 1) is not correct.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>31","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following radiation has its frequency lower than that of infra-red radiation?","images":[],"options":{"A":"Ultra-violet rays","B":"Gamma rays","C":"X-rays","D":"Radio waves"},"answer":"D","explanation":"The electromagnetic spectrum is the range of all types of EM radiation. Radiation is energy that travels and spreads out as it goes \u2013 visible light or light that we can see is one type of EM radiation. Other types of EM radiation that make up the electromagnetic spectrum are microwaves, infrared light, ultraviolet light, X-rays and gamma-rays. The order of the spectrum based on increasing frequency is: Radio waves, Microwaves, Infrared, Visible light, Ultraviolet, X-rays, Gamma rays. Therefore, the radiation with frequency lower than that of infra-red radiation is Radio waves.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>32","subject":"Physics","year":"2013","type":"Objective","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"A string under tension produces a note of frequency 14 Hz. Determine the frequency when the tension is quadrupled.","images":[],"options":{"A":"14Hz","B":"18Hz","C":"28Hz","D":"56Hz"},"answer":"C","explanation":"F = 1/2l&radic;T/U&nbsp;    Keep all other factors constant    F = K&radic;T&nbsp;, F1 = 14; F2 = ?    T1 = T1   T2 = 4T1   K = F/&radic;T&nbsp;;    K1 = K2 ,   F1/&radic;T1&nbsp; = F2/&radic;T2&nbsp;   14/F2 = &radic;T1/4T1&nbsp;    14/F2 = &radic;1/4&nbsp;    14/F2 = 1/2    F2 = 28Hz.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>33","subject":"Physics","year":"2013","type":"Objective","topic":"SOUND WAVES : VIBRATION OF AIR IN PIPE \u2013 OPEN AND CLOSED PIPES","question":"Which of the following statements about waves in pipes is correct?","images":[],"options":{"A":"For open pipes, there is only one end correction to be accounted for","B":"For close closed pipes, there are two end corrections to be accounted for","C":"Only odd harmonics are possible in closed pipes","D":"All harmonics are possible in closed pipes"},"answer":"C","explanation":"In a closed pipe, only odd harmonics are possible. This is because the pipe is closed at one end, which forces the wave to have a node (point of no displacement) at that end. At the open end, the wave must have an antinode (point of maximum displacement). This pattern of nodes and antinodes means that only odd harmonics, which have a node at one end and an antinode at the other, can exist in the pipe.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>34","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"When a person holds a negative charged metal rod and stands bare-footed on the ground, how will the charges leak?","images":[],"options":{"A":"Negative charges flows to the ground through the person's body","B":"positive charges flows from the ground through his body to neutralize the genitive charges","C":"Positive charges in the air neutralizes the negative charges the person is holding","D":"Negative charges will leak through the air"},"answer":"A","explanation":"When a person holds a negatively charged metal rod and stands bare-footed on the ground, the negative charges will flow to the ground through the person's body. This is because the ground is a good conductor and provides a path for the charges to move. This is a basic principle of electrostatics, where like charges repel and unlike charges attract. The negative charges on the rod will be attracted to the positive charges in the ground, causing a flow of charge.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>35","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"A charge of 2.0 x 10-5C experience a force of 80 N in a uniform electric field. calculate the magnitude of the electric field intensity.","images":[],"options":{"A":"8.0 x 106 NC-1","B":"4.0 x 106 NC-1","C":"4.0 x 104 NC-1","D":"2.0 x 104 NC-1"},"answer":"B","explanation":"ElectricIntensity=ForceCharge    Force (F) = 80N    Charge(Q) = 2 x 10-5C    E=802x10-5=40x105=4x106N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>36","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"An electric circuit is connected as illustrated below. Determine the equivalent emf and current flowing through the circuit respectively, neglecting the internal resistance of the cells.","images":["data:image/png;base64,"],"options":{"A":"2 V, 1.0 A","B":"2 V, 4.0 A","C":"6 V, 0.3 A","D":"6 V, 3.0 A"},"answer":"A","explanation":"For parallel connection, the equivalent voltage is = 2v    r = 0; R = 2\u03a9    E = IR    2 = I(2)    I = 1.0A","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>37","subject":"Physics","year":"2013","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"A potential difference of 12 V is applied across the ends of a 6\u03a9 resistor for 10 minutes. Determine the quantity of heat generated.","images":[],"options":{"A":"720 J","B":"1200 J","C":"14400 J","D":"43200 J"},"answer":"C","explanation":"The quantity of heat generated in a resistor can be calculated using the formula Q = I^2Rt, where Q is the heat, I is the current, R is the resistance, and t is the time. However, we don't have the current, but we have the potential difference (V) and the resistance (R). Ohm's law states that I = V/R. Substituting this into the heat formula gives Q = V^2/R * t. Substituting the given values, we get Q = (12V)^2 / 6\u03a9 * 10*60s = 14400 J. Therefore, the quantity of heat generated is 14400 J.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>38","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTRIC FIELD : SHUNT AND MULTIPLIER","question":"A galvanometer of internal resistance of 10\u03a9 has a full scale deflection with a current of 10 mA. Calculate the magnitude of the resistance required to convert it to a voltmeter capable of measuring up to 3V.","images":[],"options":{"A":"290\u03a9","B":"300\u03a9","C":"333\u03a9","D":"1000\u03a9"},"answer":"A","explanation":"VmRm=VgRg;   ImRmRm=IgRgRg  3Rm=0.01;Rm=300\u03a9   Resistance required = 300 - 10 = 290\u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>39","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Which of the following instruments is used to determine the accurate value of the electromotive force of a cell?","images":[],"options":{"A":"Voltmeter","B":"Meter bridge","C":"voltameter","D":"potentiometer"},"answer":"D","explanation":"The emf of a cell can be measured with a potentiometer which compares the unknown emf with the emf of a standard cell.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>40","subject":"Physics","year":"2013","type":"Objective","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"The direction of motion of a current-carrying conductor placed within the opposite poles of a magnet is determined using","images":[],"options":{"A":"Fleming's left-hand rule","B":"Fleming's right-hand rule.","C":"Maxwell's corkscrew rule","D":"Ampere's rule"},"answer":"A","explanation":"Fleming's left-hand rule is used to find the direction of force experienced by a current-carrying conductor in a magnetic field. The thumb, forefinger and middle finger are held at right angles to each other. The forefinger points in the direction of the magnetic field (North to South), the middle finger points in the direction of the current (positive to negative), and the thumb shows the direction of the force or motion.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>41","subject":"Physics","year":"2013","type":"Objective","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"Two straight current carrying conductors are placed near each other, which of the following diagrams correctly illustrate the magnetic field pattern formed by the conductors?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"The diagram that correctly illustrate the magnetic field pattern formed by the conductors is:","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>42","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"The capacitance of parallel plates capacitors varies","images":[],"options":{"A":"inversely as the square of the distance between the plates","B":"directly as the square of the distance between the plates","C":"inversely as the distance between the plates","D":"directly as the distance between the plates"},"answer":"C","explanation":"- Capacitance (C) \u03b1 Area (A)    - Capacitance (C) \u03b1 \u03b5o - Permittivity     -Capacitance(C)\u03b11distance(d)    C=A\u03b5od.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>43","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT","question":"Which of the following devices works on the principle of electromagnetic induction?","images":[],"options":{"A":"Carbon microphone","B":"Electric heater","C":"Moving iron ammeter","D":"Simple d.c. motor"},"answer":"D","explanation":"A simple d.c. motor works on the principle of electromagnetic induction. Electromagnetic induction is the production of an electromotive force across an electrical conductor in a changing magnetic field.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>44","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTROMAGNETIC FIELD : EDDY CURRENTS","question":"Which of the following devices doesn't make use of eddy current for its action? A/An","images":[],"options":{"A":"galvanometer","B":"speedometer","C":"induction furnace","D":"induction coil"},"answer":"A","explanation":"A galvanometer does not make use of eddy currents for its action. Eddy currents are loops of electrical current induced within conductors by a changing magnetic field in the conductor due to Faraday's law of induction. Galvanometers measure electric current, they do not rely on eddy currents.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>45","subject":"Physics","year":"2013","type":"Objective","topic":"ELECTROMAGNETIC FIELD : INDUCTANCE","question":"A coil of inductance 0.12 H and resistance 4 \u03a9, is connected across a 240v, 50Hz supply. Calculate the current through it [\u03c0 = 3.14]","images":[],"options":{"A":"6.3 A","B":"33.3 A","C":"37.2 A","D":"40.0 A"},"answer":"A","explanation":"Recall that: XL = 2\u03c0fL    XL = 2 x 3.14 x 50 x 0.12 = 37.68   I=VLXL=24037.68=6.3A.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>46","subject":"Physics","year":"2013","type":"Objective","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The work function of a metal is 2.56 \u00d7 10-19J. Calculate the frequency of a photon whose energy is required to eject from the metal an electron with a kinetic energy of 3.0eV.  [1eV = 1.6 x 10-19J; h = 6.6 x 10-34Js]","images":[],"options":{"A":"5.56 x 1019Hz","B":"1.66 x 1019Hz","C":"1.12 x 1015Hz","D":"8.42 x 1014Hz"},"answer":"C","explanation":"E = 3eV    1eV = 1.6v x 10-19J    E = 4.8 x 10-19J    Work function = 2.56 x 10-19J    Frequency(f) = ?    f = E+W / h    f = 4.8 x 10-19 + 2.56 x 10-19 / 6.6 x 10-34    f=7.36 x 10-196.6 x 10-34    f = 1.12 x 1015Hz.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2013>47","subject":"Physics","year":"2013","type":"Objective","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The minimum energy required to cause photoelectric emission when the surface of a metal is irradiated with electromagnetic radiation of suitable frequency is called","images":[],"options":{"A":"critical energy","B":"ionization energy","C":"work function","D":"planck's constant"},"answer":"C","explanation":"The minimum energy required to cause photoelectric emission when the surface of a metal is irradiated with electromagnetic radiation of suitable frequency is called the work function. The work function is a property of the material of the metal and is the minimum energy required to remove an electron from the metal surface.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>48","subject":"Physics","year":"2013","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"Which of the following particles are termed nucleons in a neutral atom?","images":[],"options":{"A":"Protons and neutrons","B":"Neutrons and electrons","C":"protons and electrons","D":"protons, electrons and neutrons"},"answer":"A","explanation":"* Nucleus is usually concentrated with protons and neutrons.    * Protons and Neutrons are generally termed 'nucleons' - meaning \"Nucleus particles\"","marks":"1","difficulty":"1"},{"id":"objective>Physics>2013>49","subject":"Physics","year":"2013","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Which of the following statements about the use of radioisotopes is not correct? They are used to","images":[],"options":{"A":"induce mutations in plants and animals to obtain new and improved varieties","B":"trace the paths of metabolic processes in plants and animals","C":"estimate the age of rocks","D":"locate broken bones"},"answer":"D","explanation":"Radioisotopes are used in a variety of applications in medical, industrial, and scientific fields. They are used to induce mutations in plants and animals to obtain new and improved varieties, trace the paths of metabolic processes in plants and animals, and estimate the age of rocks. However, they are not used to locate broken bones. Instead, X-rays, which are a form of electromagnetic radiation, are commonly used to image bones and identify fractures.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2013>50","subject":"Physics","year":"2013","type":"Objective","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Which of the following phenomena supports the theory that waves have a particles nature?","images":[],"options":{"A":"Electron diffraction","B":"Photoelectric effect","C":"Diffraction of light","D":"X-ray interference"},"answer":"B","explanation":"The photoelectric effect is a phenomenon that supports the theory that waves have a particle nature. This effect refers to the emission of electrons when light is shone onto a material. It can only be explained if light is considered to be composed of particles, because it is as if these 'light particles' are knocking the electrons out of the material. This cannot be explained if light is considered purely as a wave.","marks":"1","difficulty":"2"}];